prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?start ?startName ?taskName (EXISTS {
  ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
  ?task bbo:name ?taskName .
  FILTER(CONTAINS(LCASE(STR(?taskName)), LCASE("Probe ausliefern")))
}) AS ?taskReachableFromStart WHERE {
  ?model a bboExt:Model ;
         tai:originalId "2d225c9ff86b443c9f6bc6cfe687afbc" .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo .
  OPTIONAL { ?start bbo:name ?startName . }

  # bring taskName for display (same task)
  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .
  FILTER(CONTAINS(LCASE(STR(?taskName)), LCASE("Probe ausliefern")))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?start ?startName ?taskName ?canReachTask WHERE {
  ?model a bboExt:Model ;
         tai:originalId "2d225c9ff86b443c9f6bc6cfe687afbc" .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .
  FILTER(CONTAINS(LCASE(STR(?taskName)), LCASE("Probe ausliefern")))

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo .
  OPTIONAL { ?start bbo:name ?startName . }

  BIND(
    IF(EXISTS {
      ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
    }, true, false) AS ?canReachTask
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(DISTINCT ?start) AS ?startCount)
       (COUNT(DISTINCT ?startThatCanReachTask) AS ?startCountThatCanReachTask) 
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "2d225c9ff86b443c9f6bc6cfe687afbc" .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo .

  OPTIONAL {
    ?task a bboExt:ChoreographyTask ;
          tai:belongsTo ?choreo ;
          bbo:name ?taskName .
    FILTER(CONTAINS(LCASE(STR(?taskName)), LCASE("Probe ausliefern")))

    ?startThatCanReachTask a bboExt:StartEvent ;
          tai:belongsTo ?choreo .

    FILTER(EXISTS {
      ?startThatCanReachTask ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
    })
  }
}
LIMIT 25
